     8→import { useRole } from '../../context/RoleContext';
     9→import { ApiService } from '../../services/api';
    10→import { useAuth } from '../../context/AuthContext';
    11→import { useUI } from '../../context/UIContext';
    12→
    13→interface OnboardingViewProps { onComplete: () => void; }
    14→
    15→type Step = 'welcome' | 'firm' | 'gst' | 'firstentry' | 'done';
    16→
    17→interface FirmData {
    18→  firm_name   : string;
    19→  owner_name  : string;
    20→  phone       : string;
    21→  address     : string;
    22→  city        : string;
    23→  state       : string;
    24→  gstin       : string;
    25→  gst_enabled : boolean;
    26→}
    27→
    28→// ── Minimal input ─────────────────────────────────────────────────────────────
    29→const Input: React.FC<{
    30→  label: string; value: string; onChange: (v: string) => void;
    31→  placeholder?: string; type?: string; icon?: React.ElementType; optional?: boolean;
    32→}> = ({ label, value, onChange, placeholder, type = 'text', icon: Icon, optional }) => (
    33→  <div>
    34→    <div className="flex items-center justify-between mb-1.5">
    35→      <label className="text-[10px] font-black uppercase tracking-wider" style={{ color: 'rgba(148,163,184,0.55)' }}>{label}</label>
    36→      {optional && <span className="text-[9px]" style={{ color: 'rgba(148,163,184,0.35)' }}>Optional</span>}
    37→    </div>
    38→    <div className="relative">
    39→      {Icon && (
    40→        <div className="absolute left-3.5 top-1/2 -translate-y-1/2">
    41→          <Icon size={13} style={{ color: 'rgba(148,163,184,0.4)' }} />
    42→        </div>
    43→      )}
    44→      <input type={type} value={value} onChange={e => onChange(e.target.value)}
    45→        placeholder={placeholder}
    46→        className="w-full py-3 rounded-[14px] text-sm font-semibold outline-none transition-all"
    47→        style={{
    48→          background  : 'rgba(255,255,255,0.06)',
    49→          border      : '1px solid rgba(255,255,255,0.12)',
    50→          color       : 'rgba(240,244,255,0.9)',
    51→          paddingLeft : Icon ? '2.75rem' : '1rem',
    52→          paddingRight: '1rem',
    53→        }}
    54→      />
    55→    </div>
    56→  </div>
    57→);
    58→
    59→// ── Progress dots ─────────────────────────────────────────────────────────────
    60→const Steps: React.FC<{ steps: Step[]; current: Step }> = ({ steps, current }) => {
    61→  const idx = steps.indexOf(current);
    62→  return (
    63→    <div className="flex items-center gap-2 mb-6">
    64→      {steps.map((s, i) => (
    65→        <React.Fragment key={s}>
    66→          <div className="w-6 h-6 rounded-full flex items-center justify-center text-[9px] font-black flex-shrink-0 transition-all"
    67→            style={
    68→              i < idx  ? { background: '#10b981', color: '#fff' }
    69→            : i === idx ? { background: 'linear-gradient(135deg,#6366f1,#8b5cf6)', color: '#fff', boxShadow: '0 0 12px rgba(99,102,241,0.5)' }
    70→            :              { background: 'rgba(255,255,255,0.07)', color: 'rgba(148,163,184,0.4)' }
    71→            }>
    72→            {i < idx ? <Check size={11} /> : i + 1}
    73→          </div>
    74→          {i < steps.length - 1 && (
    75→            <div className="flex-1 h-0.5 rounded-full" style={{ background: i < idx ? '#10b981' : 'rgba(255,255,255,0.08)' }} />
    76→          )}
    77→        </React.Fragment>
    78→      ))}
    79→    </div>
    80→  );
    81→};
    82→
    83→// ── Main ──────────────────────────────────────────────────────────────────────
    84→const OnboardingView: React.FC<OnboardingViewProps> = ({ onComplete }) => {
    85→  const { role, isAdmin, adminUid } = useRole();
    86→  const { user }                    = useAuth();
    87→  const { showToast }               = useUI();
    88→
    89→  // Save target = the firm being viewed (admin's UID for staff, own UID for
    90→  // owners). Falls back to user.uid so first-time onboarding still works
    91→  // before any role document is loaded.
    92→  const dataUid = adminUid || user?.uid || '';
    93→
    94→  const [step, setStep]       = useState<Step>('welcome');
    95→  const [saving, setSaving]   = useState(false);
    96→  const [firm, setFirm]       = useState<FirmData>({
    97→    firm_name: '', owner_name: '', phone: '', address: '',
    98→    city: '', state: '', gstin: '', gst_enabled: true,
    99→  });
   100→  const [skipEntry, setSkipEntry] = useState(false);
   101→
   102→  // Pre-fill existing settings if the user has data from a previous session.
   103→  // Read from dataUid (admin namespace for staff) so the form shows the firm
   104→  // they actually have access to — not an empty profile under their own UID.
   105→  useEffect(() => {
   106→    if (!dataUid) return;
   107→    ApiService.settings.get(dataUid).then((s: any) => {
   108→      if (!s) return;
   109→      const p = s.profile || {};
   110→      const a = s.automation || {};
   111→      // Parse address back into address + city (best effort: "address, city" format)
   112→      let addr = p.address || '';
   113→      let city = '';
   114→      if (addr.includes(',')) {
   115→        const parts = addr.split(',');
   116→        city = parts.pop()?.trim() || '';
   117→        addr = parts.join(',').trim();
   118→      }
   119→      setFirm(prev => ({
   120→        ...prev,
   121→        firm_name   : p.firm_name   || prev.firm_name,
   122→        owner_name  : p.owner_name  || prev.owner_name,
   123→        phone       : p.contact     || prev.phone,
   124→        address     : addr          || prev.address,
   125→        city        : city          || prev.city,
   126→        state       : p.state       || prev.state,
   127→        gstin       : p.gstin       || prev.gstin,
   128→        gst_enabled : a.auto_calculate_gst !== undefined ? !!a.auto_calculate_gst : prev.gst_enabled,
   129→      }));
   130→    }).catch(() => {});
   131→  }, [dataUid]);
   132→
   133→  const STEPS: Step[] = isAdmin
   134→    ? ['welcome', 'firm', 'gst', 'firstentry', 'done']
   135→    : ['welcome', 'done'];
   136→
   137→  const setF = (k: keyof FirmData) => (v: string | boolean) =>
   138→    setFirm(prev => ({ ...prev, [k]: v }));
   139→
   140→  const saveFirmProfile = async () => {
   141→    if (!user || !dataUid) { showToast('Please sign in again', 'error'); return false; }
   142→    if (!firm.firm_name.trim()) { showToast('Firm name is required', 'error'); return false; }
   143→    setSaving(true);
   144→    try {
   145→      const profile = {
   146→        firm_name  : firm.firm_name.trim(),
   147→        owner_name : firm.owner_name.trim(),
   148→        phone      : firm.phone.trim(),
   149→        address    : `${firm.address}, ${firm.city}`.trim().replace(/^,\s*/, ''),
   150→        state      : firm.state.trim(),
   151→        gstin      : firm.gstin.trim(),
   152→      };
   153→      const automation = { auto_calculate_gst: firm.gst_enabled };
   154→      // Save to the firm namespace the user is actually viewing — for staff
   155→      // members this is the admin's UID, not their own.
   156→      await ApiService.settings.save(dataUid, { profile, automation } as any);
   157→      return true;
   158→    } catch (e) {
   159→      showToast('Could not save profile. You can edit it later in Settings.', 'error');
   160→      return false;
   161→    } finally { setSaving(false); }
   162→  };
   163→
   164→  const next = async () => {
   165→    const idx = STEPS.indexOf(step);
   166→    // Block step advance when the save fails so the user isn't stranded with a
   167→    // half-saved profile and no chance to re-enter their firm details.
   168→    if (step === 'gst') {
   169→      const ok = await saveFirmProfile();
   170→      if (!ok) return;
   171→    }
   172→    if (idx < STEPS.length - 1) setStep(STEPS[idx + 1]);
   173→  };
   174→
   175→  const back = () => {
   176→    const idx = STEPS.indexOf(step);
   177→    if (idx > 0) setStep(STEPS[idx - 1]);
   178→  };
   179→
   180→  // ── Render ─────────────────────────────────────────────────────────────────
   181→  return (
   182→    <div className="login-view-root auth-page-bg flex flex-col relative overflow-hidden"
   183→      style={{ minHeight: '100dvh' }}>
   184→      {/* Aurora */}
   185→      <div className="absolute inset-0 pointer-events-none">
   186→        <div className="absolute top-[-10%] left-[-5%] w-[70vw] h-[70vw] rounded-full opacity-20"
   187→          style={{ background: 'radial-gradient(circle, rgba(99,102,241,0.8), transparent 65%)' }} />
   188→        <div className="absolute bottom-[5%] right-[-10%] w-[55vw] h-[55vw] rounded-full opacity-15"
   189→          style={{ background: 'radial-gradient(circle, rgba(245,158,11,0.6), transparent 65%)' }} />
   190→      </div>
   191→
   192→      <div className="relative flex flex-col flex-1 px-5 pt-12 pb-8 max-w-sm mx-auto w-full">
   193→
   194→        {/* ── WELCOME ── */}
   195→        {step === 'welcome' && (
   196→          <div className="flex flex-col flex-1">
   197→            <div className="flex-1 flex flex-col items-center justify-center text-center gap-4">
   198→              <div className="relative mb-2">
   199→                <div className="absolute -inset-4 rounded-full opacity-40"
   200→                  style={{ background: 'radial-gradient(circle, rgba(16,185,129,0.8), transparent)' }} />
   201→                <div className="relative w-20 h-20 rounded-[28px] flex items-center justify-center"
   202→                  style={{ background: 'linear-gradient(145deg,#10b981,#059669)', boxShadow: '0 16px 40px rgba(16,185,129,0.4), inset 0 1px 0 rgba(255,255,255,0.25)' }}>
   203→                  <CheckCircle2 size={38} className="text-white" strokeWidth={2} />
   204→                </div>
   205→              </div>
   206→
   207→              <div>
   208→                <div className="flex items-center justify-center gap-2 mb-2">
   209→                  <Sparkles size={13} style={{ color: 'rgba(245,158,11,0.8)' }} />
   210→                  <span className="text-[10px] font-black uppercase tracking-[0.2em]" style={{ color: 'rgba(245,158,11,0.7)' }}>Account Ready</span>
   211→                  <Sparkles size={13} style={{ color: 'rgba(245,158,11,0.8)' }} />
   212→                </div>
   213→                <h1 className="text-[30px] font-black text-white mb-2" style={{ letterSpacing: '-0.03em' }}>
   214→                  Welcome{isAdmin ? ', Admin!' : ' Aboard!'}
   215→                </h1>
   216→                <p className="text-sm max-w-xs mx-auto" style={{ color: 'rgba(255,255,255,0.45)', lineHeight: 1.6 }}>
   217→                  {isAdmin
   218→                    ? 'Your Shopkeeper account is ready. Let\'s set up your business in 3 quick steps.'
   219→                    : 'Your staff account is set up. You have access to the dashboard, inventory, and ledger.'}
   220→                </p>
   221→              </div>
   222→
   223→              {/* Feature grid */}
   224→              <div className="w-full grid grid-cols-2 gap-3 mt-4">
   225→                {(isAdmin ? [
   226→                  { icon: ShieldCheck, title: 'Full Admin Access',    color: '#6366f1', bg: 'rgba(99,102,241,0.12)' },
   227→                  { icon: Settings,    title: 'Settings & Config',    color: '#3b82f6', bg: 'rgba(59,130,246,0.12)' },
   228→                  { icon: BarChart3,   title: 'Reports & Insights',   color: '#8b5cf6', bg: 'rgba(139,92,246,0.12)' },
   229→                  { icon: Users,       title: 'Team Management',      color: '#10b981', bg: 'rgba(16,185,129,0.12)' },
   230→                ] : [
   231→                  { icon: Users,       title: 'Staff Access',         color: '#f59e0b', bg: 'rgba(245,158,11,0.12)' },
   232→                  { icon: ShieldCheck, title: 'Dashboard & Metrics',  color: '#3b82f6', bg: 'rgba(59,130,246,0.12)' },
   233→                  { icon: Users,       title: 'Parties Management',   color: '#10b981', bg: 'rgba(16,185,129,0.12)' },
   234→                  { icon: Lock,        title: 'Limited Permissions',  color: '#ef4444', bg: 'rgba(239,68,68,0.12)' },
   235→                ]).map((f, i) => (
   236→                  <div key={i} className="rounded-[18px] p-4"
   237→                    style={{ background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)', animation: `fadeUp 0.4s ${i*80}ms both` }}>
   238→                    <div className="w-9 h-9 rounded-[12px] flex items-center justify-center mb-2.5" style={{ background: f.bg }}>
   239→                      <f.icon size={18} style={{ color: f.color }} />
   240→                    </div>
   241→                    <p className="text-[11px] font-black text-white">{f.title}</p>
   242→                  </div>
   243→                ))}
   244→              </div>
   245→            </div>
   246→
   247→            <button onClick={next}
   248→              className="w-full py-4 rounded-[20px] font-black text-white text-sm flex items-center justify-center gap-2.5 active:scale-[0.97] transition-all mt-6"
   249→              style={{ background: 'linear-gradient(135deg, #6366f1, #8b5cf6)', boxShadow: '0 12px 32px rgba(99,102,241,0.45)' }}>
   250→              {isAdmin ? <><span>Set Up My Business</span><ArrowRight size={18} /></> : <><span>Let\'s Get Started</span><ArrowRight size={18} /></>}
   251→            </button>
   252→          </div>
   253→        )}
   254→
   255→        {/* ── FIRM SETUP ── */}
   256→        {step === 'firm' && (
   257→          <div className="flex flex-col flex-1">
   258→            <Steps steps={STEPS} current={step} />
   259→            <div className="flex items-center gap-2.5 mb-5">
   260→              <div className="p-2.5 rounded-[14px]" style={{ background: 'rgba(59,130,246,0.14)', border: '1px solid rgba(59,130,246,0.25)' }}>
   261→                <Building2 size={16} style={{ color: '#60a5fa' }} />
   262→              </div>
   263→              <div>
   264→                <h2 className="text-xl font-black text-white">Business Profile</h2>
   265→                <p className="text-[11px]" style={{ color: 'rgba(148,163,184,0.5)' }}>Used in invoices & reports</p>
   266→              </div>
   267→            </div>
   268→
   269→            <div className="space-y-4 flex-1">
   270→              <Input label="Business / Firm Name *" value={firm.firm_name} onChange={setF('firm_name')}
   271→                placeholder="e.g. Sharma Traders" icon={Building2} />
   272→              <Input label="Owner Name" value={firm.owner_name} onChange={setF('owner_name')}
   273→                placeholder="e.g. Ramesh Sharma" icon={Users} optional />
   274→              <div className="grid grid-cols-2 gap-3">
   275→                <Input label="Phone" value={firm.phone} onChange={setF('phone')} placeholder="9876543210" icon={Phone} optional />
   276→                <Input label="City" value={firm.city} onChange={setF('city')} placeholder="Mumbai" icon={MapPin} optional />
   277→              </div>
   278→              <Input label="State" value={firm.state} onChange={setF('state')} placeholder="Maharashtra" optional />
   279→              <Input label="Address" value={firm.address} onChange={setF('address')} placeholder="Shop No., Street, Area" optional />
   280→            </div>
   281→
   282→            <div className="flex gap-3 mt-6">
   283→              <button onClick={back} className="px-5 py-3.5 rounded-[16px] font-black text-sm active:scale-95 transition-all"
