   288→                disabled={!firm.firm_name.trim()}
   289→                className="flex-1 py-3.5 rounded-[16px] font-black text-white text-sm flex items-center justify-center gap-2 active:scale-[0.97] transition-all disabled:opacity-40"
   290→                style={{ background: 'linear-gradient(135deg, #3b82f6, #6366f1)' }}>
   291→                Continue <ArrowRight size={16} />
   292→              </button>
   293→            </div>
   294→          </div>
   295→        )}
   296→
   297→        {/* ── GST SETUP ── */}
   298→        {step === 'gst' && (
   299→          <div className="flex flex-col flex-1">
   300→            <Steps steps={STEPS} current={step} />
   301→            <div className="flex items-center gap-2.5 mb-5">
   302→              <div className="p-2.5 rounded-[14px]" style={{ background: 'rgba(245,158,11,0.14)', border: '1px solid rgba(245,158,11,0.25)' }}>
   303→                <Percent size={16} style={{ color: '#fbbf24' }} />
   304→              </div>
   305→              <div>
   306→                <h2 className="text-xl font-black text-white">GST Settings</h2>
   307→                <p className="text-[11px]" style={{ color: 'rgba(148,163,184,0.5)' }}>Can be changed anytime in Settings</p>
   308→              </div>
   309→            </div>
   310→
   311→            <div className="space-y-4 flex-1">
   312→              {/* GST toggle */}
   313→              <button
   314→                onClick={() => setF('gst_enabled')(!firm.gst_enabled)}
