   362→                style={{ background: 'linear-gradient(135deg, #f59e0b, #d97706)' }}>
   363→                {saving ? 'Saving…' : <><span>Save & Continue</span><ArrowRight size={16} /></>}
   364→              </button>
   365→            </div>
   366→          </div>
   367→        )}
   368→
   369→        {/* ── FIRST ENTRY HINT ── */}
   370→        {step === 'firstentry' && (
   371→          <div className="flex flex-col flex-1">
   372→            <Steps steps={STEPS} current={step} />
   373→            <div className="flex items-center gap-2.5 mb-5">
   374→              <div className="p-2.5 rounded-[14px]" style={{ background: 'rgba(139,92,246,0.14)', border: '1px solid rgba(139,92,246,0.25)' }}>
   375→                <Plus size={16} style={{ color: '#a78bfa' }} />
   376→              </div>
   377→              <div>
   378→                <h2 className="text-xl font-black text-white">You're Almost Done!</h2>
