   130→export function useOptimisticDelete<T extends { id?: string }>({
   131→  userId,
   132→  collection,
   133→  queryKey,
   134→  onSuccess,
   135→  onError
   136→}: OptimisticMutationOptions<T>) {
   137→  const queryClient = useQueryClient();
   138→
   139→  return useMutation({
   140→    mutationFn: async (id: string) => {
   141→      if (!navigator.onLine) {
