   147→    },
   148→    onMutate: async (id) => {
   149→      await queryClient.cancelQueries({ queryKey });
   150→      const previousData = queryClient.getQueryData<T[]>(queryKey);
   151→
   152→      // Optimistically remove the item
   153→      queryClient.setQueryData<T[]>(queryKey, (old = []) =>
   154→        old.filter(item => item.id !== id)
   155→      );
   156→
   157→      haptic.light();
   158→      return { previousData };
   159→    },
   160→    onError: (err, _id, context) => {
   161→      if (context?.previousData) {
   162→        queryClient.setQueryData(queryKey, context.previousData);
   163→      }
   164→      haptic.error();
   165→      onError?.(err as Error);
   166→    },
   167→    onSuccess: () => {
   168→      haptic.success();
   169→      onSuccess?.();
   170→    },
   171→    onSettled: () => {
   172→      queryClient.invalidateQueries({ queryKey });
