   100→  // FIX 2: Concurrency lock prevents two callers (e.g. two sync systems or
   101→  // two online-event listeners) from processing the same queue simultaneously
   102→  // and creating duplicate Firestore documents.
   103→  async processQueue(
   104→    userId: string,
   105→    onProgress?: (processed: number, total: number) => void,
   106→  ): Promise<{ success: number; failed: number; errors: Map<string, string> }> {
   107→    const errors = new Map<string, string>();
   108→
   109→    if (!SyncLock.acquire()) {
   110→      // Concurrent call — silently skip; the in-progress run will finish.
   111→      return { success: 0, failed: 0, errors };
   112→    }
   113→    let successCount = 0;
   114→    let failedCount  = 0;
   115→    const endRun = perfMonitor.start('sync.run');
   116→
   117→    try {
   118→      const queue = SyncQueueService.getUserQueue(userId);
   119→      if (queue.length === 0) return { success: 0, failed: 0, errors };
   120→
   121→      const sorted = [...queue].sort((a, b) => {
   122→        const p = { high: 0, normal: 1, low: 2 };
   123→        return (p[a.priority] - p[b.priority]) || (a.timestamp - b.timestamp);
   124→      });
   125→
   126→      for (let i = 0; i < sorted.length; i++) {
   127→        const item = sorted[i];
   128→        onProgress?.(i + 1, sorted.length);
   129→
   130→        const endItem = perfMonitor.start('sync.item');
   131→        try {
   132→          if (item.operation === 'create') {
   133→            await ApiService.add(userId, item.collection, item.data);
   134→          } else if (item.operation === 'update' && item.docId) {
   135→            await ApiService.update(userId, item.collection, item.docId, item.data);
   136→          } else if (item.operation === 'delete' && item.docId) {
   137→            await ApiService.delete(userId, item.collection, item.docId);
   138→          }
   139→          // Remove the item from localStorage immediately after a successful
   140→          // write — NOT batched at the end — so that if the app is killed
   141→          // mid-loop the already-committed items are never replayed on the
   142→          // next start, which would create duplicate Firestore documents.
   143→          SyncQueueService.removeFromQueue(item.id);
   144→          successCount++;
   145→        } catch (error: any) {
   146→          item.retries++;
   147→          const errorMsg = error?.message || 'Unknown error';
   148→
   149→          const current = SyncQueueService.getQueue();
   150→          const qi = current.find(q => q.id === item.id);
   151→          if (qi) {
   152→            qi.retries = item.retries;
   153→            if (qi.retries >= qi.maxRetries) {
   154→              qi.error = errorMsg;
   155→              errors.set(item.id, errorMsg);
   156→              failedCount++;
   157→              // FINAL MODULE — log when an item exhausts its retries so we can
   158→              // spot recurring sync issues (auth scope, schema drift, etc.).
   159→              // Lazy-import to avoid a circular dep through firebase config.
   160→              import('./telemetryService').then(({ TelemetryService }) => {
   161→                TelemetryService.logError(userId, 'sync',
   162→                  `Sync gave up after ${qi.maxRetries} retries: ${errorMsg}`,
   163→                  { collection: item.collection, op: item.operation, docId: item.docId });
   164→              }).catch(() => { /* telemetry must never throw */ });
   165→            }
   166→            localStorage.setItem(QUEUE_KEY, JSON.stringify(current));
   167→          }
   168→        } finally {
   169→          endItem();
   170→        }
   171→      }
   172→    } finally {
   173→      endRun();
   174→      SyncLock.release();
   175→      notify();
   176→    }
   177→
   178→    return { success: successCount, failed: failedCount, errors };
   179→  },
   180→
   181→  removeFromQueue(itemId: string): void {
   182→    const filtered = SyncQueueService.getQueue().filter(item => item.id !== itemId);
   183→    localStorage.setItem(QUEUE_KEY, JSON.stringify(filtered));
   184→    notify();
   185→  },
   186→
   187→  clearQueue(): void {
   188→    localStorage.removeItem(QUEUE_KEY);
   189→    notify();
   190→  },
   191→
   192→  clearUserQueue(userId: string): void {
   193→    const filtered = SyncQueueService.getQueue().filter(item => item.userId !== userId);
   194→    localStorage.setItem(QUEUE_KEY, JSON.stringify(filtered));
   195→    notify();
   196→  },
   197→
   198→  getFailedItems(userId: string): QueueItem[] {
   199→    return SyncQueueService.getUserQueue(userId).filter(item => item.error);
   200→  },
   201→
   202→  async retryFailed(
   203→    userId: string,
   204→    onProgress?: (processed: number, total: number) => void,
   205→  ) {
   206→    const queue = SyncQueueService.getQueue();
   207→    queue
   208→      .filter(item => item.userId === userId && item.error)
   209→      .forEach(item => { item.error = undefined; item.retries = 0; });
   210→    localStorage.setItem(QUEUE_KEY, JSON.stringify(queue));
   211→    notify();
   212→    return SyncQueueService.processQueue(userId, onProgress);
   213→  },
   214→};
