/**
 * WRITE TIMEOUT GUARD
 * ─────────────────────────────────────────────────────────────────────────────
 * On Android WebView under memory pressure, Firestore's persistentLocalCache
 * writes to IndexedDB can hang indefinitely — the Promise never resolves AND
 * never rejects. This leaves any UI that does `setLoading(true)` → `await write`
 * → `setLoading(false)` frozen on "Saving…" forever.
 *
 * This wrapper races every write against a hard 15-second timeout. If the
 * timeout fires first we reject with a structured WRITE_TIMEOUT error so the
 * caller can fall back to the offline sync-queue instead of hanging the UI.
 * 15 s is generous — a healthy IndexedDB write resolves in < 500 ms.
 */
const WRITE_TIMEOUT_MS = 15_000;

function withWriteTimeout<T>(promise: Promise<T>): Promise<T> {
  return Promise.race([
    promise,
    new Promise<T>((_, reject) =>
      setTimeout(() => {
        const err: any = new Error(
          'Firestore write timed out — IndexedDB may be locked (Android WebView memory pressure). Falling back to offline queue.',
        );
        err.code = 'WRITE_TIMEOUT';
        reject(err);
      }, WRITE_TIMEOUT_MS),
    ),
  ]);
}

