  // Network / IndexedDB timeout errors must NOT block onboarding.
  // The error toast already tells the user they can update in Settings.
  // Returning true here lets the wizard advance — the profile was either
  // queued locally by Firestore's offline layer or can be set later.
  const isTimeout = e?.code === 'WRITE_TIMEOUT';
  showToast(
    isTimeout
      ? 'Save timed out — your profile will sync when connection improves. You can also update it in Settings.'
      : 'Could not save profile. You can edit it later in Settings.',
    'warning',
  );
  return true;
} finally { setSaving(false); }

