            className="w-full py-3 rounded-[14px] text-sm font-semibold outline-none transition-all"
            style={{
              background   : 'rgba(255,255,255,0.06)',
              border       : '1px solid rgba(255,255,255,0.12)',
              color        : 'rgba(240,244,255,0.9)',
              paddingLeft  : '2.75rem',
              paddingRight : firm.gstin.length === 15 ? '7rem' : '1rem',
            }}
          />
          {/* Fetch button — only when GSTIN is complete */}
          {firm.gstin.length === 15 && (
            <button
              onClick={handleGstFetch}
              disabled={gstFetching}
              className="absolute right-2 top-1/2 -translate-y-1/2 flex items-center gap-1.5 px-3 py-1.5 rounded-[10px] font-black text-[10px] transition-all active:scale-95 disabled:opacity-60"
              style={{
                background: gstFetchResult
                  ? 'rgba(16,185,129,0.18)'
                  : 'linear-gradient(135deg,rgba(99,102,241,0.9),rgba(139,92,246,0.9))',
                color: gstFetchResult ? '#34d399' : '#fff',
                border: gstFetchResult ? '1px solid rgba(16,185,129,0.3)' : 'none',
              }}>
              {gstFetching
                ? <><Loader2 size={10} className="animate-spin" /><span>Fetching…</span></>
                : gstFetchResult
                  ? <><CheckCircle size={10} /><span>Fetched</span></>
                  : <><Search size={10} /><span>Auto Fetch</span></>
              }
            </button>
          )}
        </div>

        {/* Validation line */}
        {firm.gstin.length === 15 && !gstFetchError && (
          <p className="text-[9px] mt-1 font-bold" style={{ color: 'rgba(52,211,153,0.8)' }}>✓ Format looks valid</p>
        )}
        {firm.gstin.length > 0 && firm.gstin.length < 15 && (
          <p className="text-[9px] mt-1 font-bold" style={{ color: 'rgba(251,191,36,0.8)' }}>GSTIN must be 15 characters ({15 - firm.gstin.length} more)</p>
        )}

        {/* Fetch error */}
        {gstFetchError && (
          <div className="mt-2 flex items-start gap-2 p-3 rounded-[12px]"
            style={{ background: 'rgba(239,68,68,0.08)', border: '1px solid rgba(239,68,68,0.2)' }}>
            <AlertCircle size={12} className="flex-shrink-0 mt-0.5" style={{ color: '#f87171' }} />
            <p className="text-[10px] font-bold" style={{ color: 'rgba(248,113,113,0.9)' }}>{gstFetchError}</p>
          </div>
        )}

        {/* Fetch success card */}
        {gstFetchResult && (
          <div className="mt-3 rounded-[16px] overflow-hidden"
            style={{ background: 'rgba(16,185,129,0.07)', border: '1px solid rgba(16,185,129,0.2)' }}>
            <div className="px-3.5 pt-3 pb-1 flex items-center justify-between">
              <div className="flex items-center gap-1.5">
                <CheckCircle size={11} style={{ color: '#34d399' }} />
                <span className="text-[9px] font-black uppercase tracking-wider" style={{ color: '#34d399' }}>
                  Details Fetched
                </span>
              </div>
              <span className="text-[8px] font-bold px-2 py-0.5 rounded-full"
                style={{
                  background: gstFetchResult.status?.toLowerCase() === 'active'
                    ? 'rgba(16,185,129,0.18)' : 'rgba(251,191,36,0.18)',
                  color: gstFetchResult.status?.toLowerCase() === 'active' ? '#34d399' : '#fbbf24',
                }}>
                GST: {gstFetchResult.status || 'Unknown'}
              </span>
            </div>

            <div className="px-3.5 pb-3 space-y-1.5 mt-1">
              {gstFetchResult.legalName && (
                <div>
                  <p className="text-[8px] uppercase font-black tracking-wider mb-0.5"
                    style={{ color: 'rgba(148,163,184,0.4)' }}>Legal Name</p>
                  <p className="text-xs font-black text-white">{gstFetchResult.legalName}</p>
                </div>
              )}
              {gstFetchResult.tradeName && gstFetchResult.tradeName !== gstFetchResult.legalName && (
                <div>
                  <p className="text-[8px] uppercase font-black tracking-wider mb-0.5"
                    style={{ color: 'rgba(148,163,184,0.4)' }}>Trade Name</p>
                  <p className="text-[11px] font-semibold" style={{ color: 'rgba(203,213,225,0.8)' }}>{gstFetchResult.tradeName}</p>
                </div>
              )}
              {(gstFetchResult.address || gstFetchResult.state) && (
                <div>
                  <p className="text-[8px] uppercase font-black tracking-wider mb-0.5"
                    style={{ color: 'rgba(148,163,184,0.4)' }}>Address</p>
                  <p className="text-[10px] font-semibold" style={{ color: 'rgba(148,163,184,0.7)' }}>
                    {[gstFetchResult.address, gstFetchResult.state].filter(Boolean).join(' · ')}
                  </p>
                </div>
              )}

              {/* Auto-filled summary */}
              {gstFetchResult.filledFields.length > 0 ? (
                <div className="mt-2 flex items-center gap-1.5 flex-wrap">
                  <span className="text-[8px] font-bold" style={{ color: 'rgba(148,163,184,0.5)' }}>Auto-filled:</span>
                  {gstFetchResult.filledFields.map(f => (
                    <span key={f} className="text-[8px] font-black px-1.5 py-0.5 rounded-md"
                      style={{ background: 'rgba(16,185,129,0.15)', color: '#6ee7b7' }}>
                      {f}
                    </span>
                  ))}
                </div>
              ) : (
                /* Fields were already set — offer overwrite */
                <div className="mt-2 flex items-center justify-between gap-2">
                  <p className="text-[9px]" style={{ color: 'rgba(148,163,184,0.5)' }}>
                    Your existing details were kept.
                  </p>
                  <button
                    onClick={handleGstFetchOverwrite}
                    className="flex items-center gap-1 text-[8px] font-black px-2 py-1 rounded-[8px] active:scale-95 transition-all"
                    style={{ background: 'rgba(99,102,241,0.18)', color: '#a5b4fc', border: '1px solid rgba(99,102,241,0.25)' }}>
                    <RefreshCw size={8} /> Overwrite
                  </button>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      <div className="rounded-[16px] p-3.5" style={{ background: 'rgba(59,130,246,0.08)', border: '1px solid rgba(59,130,246,0.18)' }}>
        <p className="text-[10px] font-bold" style={{ color: 'rgba(147,197,253,0.7)' }}>
          💡 Enter your GSTIN and tap <strong style={{ color: 'rgba(165,180,252,0.9)' }}>Auto Fetch</strong> to fill your business name, address &amp; state automatically. GST info also enables CGST/SGST breakdown on invoices.
        </p>
      </div>
    </div>

    <div className="flex gap-3 mt-6">
      <button onClick={back} className="px-5 py-3.5 rounded-[16px] font-black text-sm active:scale-95 transition-all"
        style={{ background: 'rgba(255,255,255,0.08)', border: '1px solid rgba(255,255,255,0.12)', color: 'rgba(203,213,225,0.8)' }}>
        <ArrowLeft size={16} />
      </button>
      <button onClick={next} disabled={saving}
        className="flex-1 py-3.5 rounded-[16px] font-black text-white text-sm flex items-center justify-center gap-2 active:scale-[0.97] transition-all disabled:opacity-60"
        style={{ background: 'linear-gradient(135deg, #f59e0b, #d97706)' }}>
        {saving ? 'Saving…' : <><span>Save & Continue</span><ArrowRight size={16} /></>}
      </button>
    </div>
  </div>
)}

