const handleGstFetch = async () => {
  if (firm.gstin.length !== 15) return;
  setGstFetching(true);
  setGstFetchError('');
  setGstFetchResult(null);
  try {
    const res = await GSTService.fetchDetails(firm.gstin.toUpperCase());
    const name    = res.legalName || res.tradeName || '';
    const address = res.address   || '';
    const state   = res.state     || '';
    const filled: string[] = [];

    setFirm(prev => {
      const next = { ...prev };
      if (name    && !prev.firm_name) { next.firm_name = name;    filled.push('Business Name'); }
      if (address && !prev.address)   { next.address   = address; filled.push('Address'); }
      if (state   && !prev.state)     { next.state     = state;   filled.push('State'); }
      return next;
    });
    setGstFetchResult({ ...res, legalName: name, filledFields: filled });
  } catch (e: any) {
    setGstFetchError(e.message || 'Could not fetch GST details.');
  } finally {
    setGstFetching(false);
  }
};

const handleGstFetchOverwrite = () => {
  if (!gstFetchResult) return;
  setFirm(prev => ({
    ...prev,
    firm_name : gstFetchResult.legalName  || prev.firm_name,
    address   : gstFetchResult.address    || prev.address,
    state     : gstFetchResult.state      || prev.state,
  }));
  setGstFetchResult(prev => prev ? { ...prev, filledFields: ['Business Name', 'Address', 'State'] } : prev);
};

