    16→ *  isPickerAvailable()     — true if one-shot picker is available (web only).
    17→ * ─────────────────────────────────────────────────────────────────────────────
    18→ */
    19→import { Capacitor } from '@capacitor/core';
    20→
    21→export interface AppContact {
    22→  name:  string;
    23→  phone: string;
    24→}
    25→
    26→let _cachedContacts: AppContact[] | null = null;
    27→
    28→/* ── Bulk load — Capacitor native only ──────────────────────────────────── */
    29→export async function getAllContactsNative(): Promise<AppContact[]> {
    30→  if (_cachedContacts !== null) return _cachedContacts;
    31→  if (!Capacitor.isNativePlatform()) return [];
    32→
    33→  try {
    34→    const { Contacts } = await import('@capacitor-community/contacts' as any);
    35→
    36→    // Check existing permission state first — avoids redundant prompts.
    37→    // Accept both 'granted' (Android) and 'authorized' (iOS legacy) as positive states.
    38→    const GRANTED = ['granted', 'authorized'];
    39→    let alreadyGranted = false;
    40→    try {
    41→      const currentPerm = await Contacts.checkPermissions();
    42→      const state: string = currentPerm?.contacts ?? '';
    43→      alreadyGranted = GRANTED.includes(state);
    44→      // 'denied' / 'restricted' — no point asking again, bail out silently
    45→      if (!alreadyGranted && (state === 'denied' || state === 'restricted')) return [];
    46→    } catch (_) { /* checkPermissions may not exist in older plugin builds */ }
    47→
    48→    if (!alreadyGranted) {
    49→      const perm = await Contacts.requestPermissions();
    50→      const grantedState: string = perm?.contacts ?? '';
    51→      if (!GRANTED.includes(grantedState)) return [];
    52→    }
    53→
    54→    const result = await Contacts.getContacts({
    55→      projection: { name: true, phones: true },
    56→    });
    57→
    58→    const contacts = (result?.contacts ?? []).flatMap((c: any) => {
    59→      const name = c.name?.display || c.name?.given || c.name?.family || '';
    60→      // Handle API differences across plugin versions: phones vs phoneNumbers, number vs value
    61→      const rawPhones: any[] = c.phones ?? c.phoneNumbers ?? [];
    62→      const phones = rawPhones
    63→        .map((p: any) => ((p.number ?? p.value ?? '')).trim())
    64→        .filter(Boolean);
    65→      if (!name) return [];
    66→      return phones.length > 0
    67→        ? phones.map((ph: string) => ({ name, phone: ph }))
    68→        : [{ name, phone: '' }];
    69→    });
    70→
    71→    _cachedContacts = contacts;
    72→    return _cachedContacts;
    73→  } catch (e) {
    74→    console.warn('Capacitor Contacts error:', e);
    75→    // Do not cache on error — allow a retry on next form open
    76→    return [];
    77→  }
    78→}
    79→
    80→/* ── One-shot picker — Web Contact Picker API only ──────────────────────── */
    81→export async function pickContactFromDevice(): Promise<AppContact | null> {
    82→  // Web Contact Picker API (Chrome Android ≥ 80)
    83→  if ('contacts' in navigator && 'ContactsManager' in window) {
    84→    try {
    85→      const results = await (navigator as any).contacts.select(['name', 'tel'], { multiple: false });
    86→      if (!results || results.length === 0) return null;
    87→      const c     = results[0];
    88→      const name  = (c.name ?? [])[0] ?? '';
    89→      const phone = ((c.tel ?? [])[0] ?? '').trim();
    90→      if (!name) return null;
    91→      return { name, phone };
    92→    } catch (e) {
    93→      console.warn('Web Contact Picker error:', e);
    94→      return null;
    95→    }
    96→  }
    97→
    98→  return null;
    99→}
