   101→/* ── Availability checks ─────────────────────────────────────────────────── */
   102→/** True if we can bulk-load contacts in background (Capacitor native only) */
   103→export function isNativeContacts(): boolean {
   104→  return Capacitor.isNativePlatform();
   105→}
   106→
   107→/** True if the one-shot web picker is available */
   108→export function isPickerAvailable(): boolean {
   109→  if ('contacts' in navigator && 'ContactsManager' in window) return true;
   110→  return false;
   111→}
   112→
   113→/* ── Legacy aliases ──────────────────────────────────────────────────────── */
   114→export const getAllContacts       = getAllContactsNative;
   115→export const isContactsAvailable = isPickerAvailable;
   116→
   117→/* ── Search — up to 8 suggestions, startsWith ranked first ──────────────── */
   118→export function searchContacts(contacts: AppContact[], query: string): AppContact[] {
   119→  if (!query || !query.trim()) return [];
   120→  const q       = query.toLowerCase().trim();
   121→  const qDigits = q.replace(/\D/g, ''); // digits only for phone matching
   122→
   123→  const startsWith = contacts.filter(c => c.name.toLowerCase().startsWith(q));
   124→  const includes   = contacts.filter(c => {
   125→    if (c.name.toLowerCase().startsWith(q)) return false;
   126→    if (c.name.toLowerCase().includes(q)) return true;
   127→    // Phone matching: strip non-digits from both sides so spaces / dashes / country codes don't matter
   128→    if (qDigits.length >= 3) {
   129→      const phoneDigits = c.phone.replace(/\D/g, '');
   130→      if (phoneDigits.includes(qDigits)) return true;
   131→    }
   132→    return false;
   133→  });
   134→
   135→  return [...startsWith, ...includes].slice(0, 8);
   136→}
   137→
   138→/** Clear cache — call when app resumes or permissions change */
   139→export function clearContactCache(): void {
   140→  _cachedContacts = null;
   141→}
